const markMagicLinkUsed = `-- name: MarkMagicLinkUsed :execrows
UPDATE auth_magic_links
SET used_at = $1
WHERE id = $2
  AND used_at IS NULL
  AND (
    CASE
      WHEN strpos(expires_at, '.') = 0 THEN replace(expires_at, 'Z', '.000000000Z')
      ELSE substring(expires_at from 1 for strpos(expires_at, '.')) ||
           substring(substring(expires_at from strpos(expires_at, '.') + 1 for strpos(expires_at, 'Z') - strpos(expires_at, '.') - 1) || '000000000' from 1 for 9) ||
           'Z'
    END
  ) > (
    CASE
      WHEN strpos($3::text, '.') = 0 THEN replace($3::text, 'Z', '.000000000Z')
      ELSE substring($3::text from 1 for strpos($3::text, '.')) ||
           substring(substring($3::text from strpos($3::text, '.') + 1 for strpos($3::text, 'Z') - strpos($3::text, '.') - 1) || '000000000' from 1 for 9) ||
           'Z'
    END
  )
`

type MarkMagicLinkUsedParams struct {
	UsedAt sql.NullString `json:"used_at"`
	ID     string         `json:"id"`
	Now    string         `json:"now"`
}

func (q *Queries) MarkMagicLinkUsed(ctx context.Context, arg MarkMagicLinkUsedParams) (int64, error) {
	result, err := q.db.ExecContext(ctx, markMagicLinkUsed, arg.UsedAt, arg.ID, arg.Now)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected()
}

const membershipRolesForUpdate = `-- name: MembershipRolesForUpdate :many
SELECT user_id, role
FROM workspace_members
WHERE workspace_id = $1
  AND user_id IN ($2, $3)
ORDER BY user_id
FOR UPDATE
`

type MembershipRolesForUpdateParams struct {
	WorkspaceID  string `json:"workspace_id"`
	ActorUserID  string `json:"actor_user_id"`
	TargetUserID string `json:"target_user_id"`
}

type MembershipRolesForUpdateRow struct {
	UserID string `json:"user_id"`
	Role   string `json:"role"`
}

func (q *Queries) MembershipRolesForUpdate(ctx context.Context, arg MembershipRolesForUpdateParams) ([]MembershipRolesForUpdateRow, error) {
	rows, err := q.db.QueryContext(ctx, membershipRolesForUpdate, arg.WorkspaceID, arg.ActorUserID, arg.TargetUserID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []MembershipRolesForUpdateRow
	for rows.Next() {
		var i MembershipRolesForUpdateRow
		if err := rows.Scan(&i.UserID, &i.Role); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const pruneEvents = `-- name: PruneEvents :execrows
DELETE FROM events AS e
WHERE e.workspace_id = $1
  AND (
    NULLIF($2::text, '') IS NULL
    OR (
      CASE
        WHEN strpos(e.created_at, '.') = 0 THEN replace(e.created_at, 'Z', '.000000000Z')
        ELSE substring(e.created_at from 1 for strpos(e.created_at, '.')) ||
             substring(substring(e.created_at from strpos(e.created_at, '.') + 1 for strpos(e.created_at, 'Z') - strpos(e.created_at, '.') - 1) || '000000000' from 1 for 9) ||
             'Z'
      END
    ) < (
      CASE
        WHEN strpos(NULLIF($2::text, ''), '.') = 0 THEN replace(NULLIF($2::text, ''), 'Z', '.000000000Z')
        ELSE substring(NULLIF($2::text, '') from 1 for strpos(NULLIF($2::text, ''), '.')) ||
             substring(substring(NULLIF($2::text, '') from strpos(NULLIF($2::text, ''), '.') + 1 for strpos(NULLIF($2::text, ''), 'Z') - strpos(NULLIF($2::text, ''), '.') - 1) || '000000000' from 1 for 9) ||
             'Z'
      END
    )
  )
  AND e.id NOT IN (
    SELECT kept.id
    FROM events AS kept
    WHERE kept.workspace_id = $1
    ORDER BY kept.cursor DESC
    LIMIT $3
  )
`

type PruneEventsParams struct {
	WorkspaceIDArg string `json:"workspace_id_arg"`
	Before         string `json:"before"`
	KeepLatest     int32  `json:"keep_latest"`
}

func (q *Queries) PruneEvents(ctx context.Context, arg PruneEventsParams) (int64, error) {
	result, err := q.db.ExecContext(ctx, pruneEvents, arg.WorkspaceIDArg, arg.Before, arg.KeepLatest)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected()
}

